            summary="A-share realtime crosscheck summary is implemented as a read-only Experimental aggregation over TDX, Tencent qt, and WorkBuddy lanes.",
            dependencies=["brain_core.trading_domain", "SYSTEM_REPLICATION_FOR_CODEX.md"],
            quality_score=0.71,
            evidence_level="crosscheck_summary",
            source_reliability=source.reliability,
