    def report_a_share_real_data_source_registry(self, payload: dict[str, Any] | None = None) -> dict[str, Any]:
        payload = payload or {}
        symbol = str(payload.get("symbol", "300418") or "300418").upper()
        timeframe = str(payload.get("timeframe", "1d") or "1d")
        authority_doc = self._a_share_authority_document_path(payload)
        routes = self._a_share_real_data_source_routes()
        preferred_source_chain = [
            str(item.get("source_key", "") or "")
            for item in routes
            if str(item.get("implementation_status", "") or "") != "Future Roadmap"
        ]
        changed = False
        source_records: list[dict[str, Any]] = []
        source_record_ids: list[str] = []
        for route in routes:
            source_key = str(route.get("source_key", "") or "")
