            recommendation=str(breakout_raw_backtest.get("suggestion", {}).get("verdict", "wait")),
            quality_score=clamp(0.5 + max(-0.2, min(0.25, float(breakout_raw_backtest["total_return"])))),
            evidence_level="backtest",
            source_reliability=market_source.reliability,
            freshness=0.8,
            validation_status="backtested",
            out_of_sample_result=breakout_split_summary["out_of_sample_result"],
