            final_equity=float(vwap_proxy_raw_backtest["final_equity"]),
            risk_adjusted_score=float(vwap_proxy_raw_backtest["risk_adjusted_score"]),
            cost_pct=total_cost_pct,
            summary=f"Replay {symbol} with daily-proxy VWAP research candidate over {vwap_proxy_raw_backtest['bars']} bars.",
            recommendation=str(vwap_proxy_raw_backtest.get("suggestion", {}).get("verdict", "wait")),
